TableColumns($table,$columns){$issues=[];$column_names=array_column($columns,'Field');switch($table){case'personil':$required=['id','nama','nrp','is_deleted','created_at','updated_at'];$optional=['nip','JK','status_ket','alasan_status','tanggal_lahir','tempat_lahir','tanggal_masuk','tanggal_pensiun','no_karpeg','id_pangkat','id_jabatan','id_bagian','id_unsur','id_jenis_pegawai'];forforeach($requiredas$req){if(!in_array($req,$column_names)){$issues[]="Missingrequiredcolumn:$req";}}/Checkdatatypesforforeach($columnsas$col){if($col'\1\'=>=='id'&&$col['Type']!=='int(11)'){$issues[]="IDcolumnshouldbeint(11)";}if($col'\1\'=>=='nrp'&&!strpos($col['Type'],'varchar')){$issues[]="NRPcolumnshouldbevarchar";}if($col'\1\'=>=='is_deleted'&&$col['Type']!=='tinyint(1)'){$issues[]="is_deletedcolumnshouldbetinyint(1)";}}break;case'unsur':$required=['id','nama_unsur','kode_unsur','urutan','is_active','created_at','updated_at'];forforeach($requiredas$req){if(!in_array($req,$column_names)){$issues[]="Missingrequiredcolumn:$req";}}/Checkuniquenessconstraintsif(!in_array('kode_unsur',$column_names)){$issues[]="Missingkode_unsurcolumn";}break;case'bagian':$required=['id','nama_bagian','id_unsur','urutan','is_active','created_at','updated_at'];forforeach($requiredas$req){if(!in_array($req,$column_names)){$issues[]="Missingrequiredcolumn:$req";}}/Checkforeignkeyif(!in_array('id_unsur',$column_names)){$issues[]="Missingid_unsurforeignkeycolumn";}break;case'jabatan':$required=['id','nama_jabatan','id_unsur','is_active','created_at','updated_at'];forforeach($requiredas$req){if(!in_array($req,$column_names)){$issues[]="Missingrequiredcolumn:$req";}}/Checkforeignkeyif(!in_array('id_unsur',$column_names)){$issues[]="Missingid_unsurforeignkeycolumn";}break;case'pangkat':$required=['id','nama_pangkat','singkatan','level_pangkat'];forforeach($requiredas$req){if(!in_array($req,$column_names)){$issues[]="Missingrequiredcolumn:$req";}}break;case'master_jenis_pegawai':$required=['id','kategori'];forforea