ations=[];/Checkformissingforeignkeysif(!empty($this->results['missing_foreign_keys'])){$recommendations[]='Addmissingforeignkeyconstraints:'.implode(',',$this->results['missing_foreign_keys']);}/Checkformissingindexesif(!empty($this->results['missing_indexes'])){$recommendations[]='Addmissingindexesforbetterperformance:'.implode(',',$this->results['missing_indexes']);}/Checkfororphanedrecordsif(!empty($this->results['relationships']['orphaned_records'])){$orphaned=array_filter($this->results['relationships']['orphaned_records']);if(!empty($orphaned)){$recommendations[]='Cleanuporphanedrecordsinrelationships';}}/Checktableissuesforforeach($this->results['tables']as$table=>$info){if(!empty($info['issues'])){$recommendations[]="Fixissuesintable'$table':".implode(',',$info['issues']);}}return$recommendations;}}/APIendpointfordatabasestructurecheckif(isset(filter_input(INPUT_GET,'\1\',FILTER_DEFAULT))&&filter_input(INPUT_GET,'\1\',FILTER_DEFAULT)==='check_structure'){try{$checker=newDatabaseStructureChecker();$result=$checker->checkStructure();echojson_encode(APIResponse::success($result,'Databasestructurecheckcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
